module RefModule (CLK, RST, LOAD, D, Q);
input CLK, RST, LOAD;
input [7:0] D;
output reg Q;
reg [7:0] obf_shift_reg;

always @(posedge CLK or posedge RST) begin
    if (RST)
        obf_shift_reg <= 8'b00000000;
    else if (LOAD)
        obf_shift_reg <= D;
    else
        obf_shift_reg <= obf_shift_reg >> 1;
end

always @(*) begin
    Q = obf_shift_reg[0];
end

endmodule
